#include <vector>
using namespace std;

long long solve(long long n, vector<vector<long long>> edges, long long k) {
    long long max_time = 0;
    for (auto& e : edges) {
        max_time = max(max_time, e[2]);
    }
    long long low = 0, high = max_time;
    while (low < high) {
        long long mid = (low + high) / 2;
        vector<long long> parent(n);
        vector<long long> rank(n, 1);
        long long count = n;
        auto find = [&](long long x) {
            if (parent[x] != x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        };
        auto union_ = [&](long long x, long long y) {
            long long root_x = find(x);
            long long root_y = find(y);
            if (root_x == root_y) return false;
            if (rank[root_x] < rank[root_y]) {
                parent[root_x] = root_y;
            } else {
                parent[root_y] = root_x;
                if (rank[root_x] == rank[root_y]) {
                    rank[root_x]++;
                }
            }
            count--;
            return true;
        };
        for (auto& e : edges) {
            if (e[2] > mid) {
                union_(e[0], e[1]);
            }
        }
        if (count >= k) {
            high = mid;
        } else {
            low = mid + 1;
        }
    }
    return low;
}

